module binary_counter (
	input clk,
	input reset,
	input enable,
	output [1:0] count
);reg [1:0] count_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset)
		count_reg <= 2'b00;
	else if (enable)
		count_reg <= count_reg + 1;
end

assign count = count_reg;

endmodule
